+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number; min: number}
+	| {type: 'auto'};
+
+type Placement = {start?: number; end?: number};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	const values = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return values.map(value => {
+		if (value === 'auto') return {type: 'auto'};
+		const minmax = /^minmax\\(\\s*(-?\\d+(?:\\.\\d+)?)\\s*,\\s*(-?\\d+(?:\\.\\d+)?(?:fr)?)\\s*\\)$/.exec(value);
+		if (minmax) {
+			const min = Number(minmax[1]);
+			return minmax[2].endsWith('fr')
+				? {type: 'fr', value: Number.parseFloat(minmax[2]), min}
+				: {type: 'fixed', value: Number(minmax[2])};
+		}
+
+		if (value.endsWith('fr')) return {type: 'fr', value: Number.parseFloat(value), min: 0};
+		return {type: 'fixed', value: Number(value)};
+	}).filter(track => Number.isFinite(track.type === 'auto' ? 0 : track.value));
+};
+
+const parsePlacement = (value: number | string | undefined): Placement => {
+	if (typeof value === 'number') return {start: value - 1, end: value};
+	if (!value) return {};
+	const parts = value.split('/').map(part => Number.parseInt(part.trim(), 10));
+	if (!Number.isFinite(parts[0])) return {};
+	return parts.length === 1 || !Number.isFinite(parts[1])
+		? {start: parts[0] - 1, end: parts[0]}
+		: {start: parts[0] - 1, end: parts[1] - 1};
+};
+
+const resolveTracks = (tracks: Track[], available: number, gap: number, autoSizes: number[]): number[] => {
+	const gaps = Math.max(0, tracks.length - 1) * gap;
+	const fixed = tracks.reduce((sum, track, index) => sum + (track.type === 'fixed' ? track.value : track.type === 'auto' ? (autoSizes[index] ?? 0) : track.min), 0);
+	const frTotal = tracks.reduce((sum, track) => sum + (track.type === 'fr' ? track.value : 0), 0);
+	const remaining = Math.max(0, available - gaps - fixed);
+	return tracks.map((track, index) => track.type === 'fixed' ? track.value : track.type === 'auto' ? (autoSizes[index] ?? 0) : track.min + (frTotal === 0 ? 0 : remaining * track.value / frTotal));
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const result = offset;
+		offset += size + gap;
+		return result;
+	});
+};
+
+const gridChildren = (node: DOMElement): DOMElement[] => node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+
+const layoutGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode;
+	if (!yogaNode || node.style.display !== 'grid') return;
+	const children = gridChildren(node);
+	let columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns = [{type: 'auto'}];
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const placements: Array<{node: DOMElement; column: Placement; row: Placement}> = [];
+	let cursorColumn = 0;
+	let cursorRow = 0;
+	for (const child of children) {
+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		const startColumn = column.start ?? cursorColumn;
+		const startRow = row.start ?? cursorRow;
+		column.start = startColumn;
+		column.end ??= startColumn + 1;
+		row.start = startRow;
+		row.end ??= startRow + 1;
+		placements.push({node: child, column, row});
+		cursorColumn = startColumn + 1;
+		cursorRow = startRow;
+		if (cursorColumn >= columns.length) {
+			cursorColumn = 0;
+			cursorRow++;
+		}
+	}
+
+	const requiredRows = Math.max(0, ...placements.map(placement => placement.row.end ?? 0));
+	const rows = parseTracks(node.style.gridTemplateRows);
+	while (rows.length < requiredRows) rows.push({type: 'auto'});
+	const columnAutoSizes = columns.map((track, index) => track.type === 'auto' ? Math.max(0, ...placements.filter(placement => placement.column.start === index && placement.column.end === index + 1).map(placement => placement.node.yogaNode!.getComputedWidth())) : 0);
+	const rowAutoSizes = rows.map((track, index) => track.type === 'auto' ? Math.max(0, ...placements.filter(placement => placement.row.start === index && placement.row.end === index + 1).map(placement => placement.node.yogaNode!.getComputedHeight())) : 0);
+	const width = yogaNode.getComputedWidth();
+	const height = yogaNode.getComputedHeight();
+	const columnSizes = resolveTracks(columns, width, columnGap, columnAutoSizes);
+	const rowSizes = resolveTracks(rows, node.style.height === undefined ? 0 : height, rowGap, rowAutoSizes);
+	const columnOffsets = offsets(columnSizes, columnGap);
+	const rowOffsets = offsets(rowSizes, rowGap);
+
+	if (node.style.height === undefined) yogaNode.setHeight(rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rows.length - 1) * rowGap);
+	for (const placement of placements) {
+		const child = placement.node.yogaNode!;
+		const columnStart = placement.column.start ?? 0;
+		const columnEnd = Math.min(placement.column.end ?? columnStart + 1, columnSizes.length);
+		const rowStart = placement.row.start ?? 0;
+		const rowEnd = Math.min(placement.row.end ?? rowStart + 1, rowSizes.length);
+		const itemWidth = columnSizes.slice(columnStart, columnEnd).reduce((sum, size) => sum + size, 0) + Math.max(0, columnEnd - columnStart - 1) * columnGap;
+		const itemHeight = rowSizes.slice(rowStart, rowEnd).reduce((sum, size) => sum + size, 0) + Math.max(0, rowEnd - rowStart - 1) * rowGap;
+		child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.setPosition(Yoga.EDGE_LEFT, columnOffsets[columnStart] ?? 0);
+		child.setPosition(Yoga.EDGE_TOP, rowOffsets[rowStart] ?? 0);
+		child.setWidth(itemWidth);
+		if (rows[rowStart]?.type !== 'auto' || rowEnd - rowStart > 1) child.setHeight(itemHeight);
+	}
+};
+
+const visit = (node: DOMElement): void => {
+	layoutGrid(node);
+	for (const child of gridChildren(node)) visit(child);
+};
+
+export const calculateLayoutWithGrid = (root: DOMElement, width?: number, height?: number): void => {
+	for (let iteration = 0; iteration < 3; iteration++) {
+		root.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
+		visit(root);
+	}
+	root.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
+};
